import{_ as n,C as o,o as l,c as s,E as t,w as a,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const w=JSON.parse('{"title":"Switzerland Legal Rights","description":"Legal rights for transgender people in Switzerland","frontmatter":{"layout":"doc","title":"Switzerland Legal Rights","description":"Legal rights for transgender people in Switzerland"},"headers":[],"relativePath":"europe/switzerland/legal-rights.md","filePath":"europe/switzerland/legal-rights.md","lastUpdated":null}'),c={name:"europe/switzerland/legal-rights.md"};function h(u,e,g,m,p,f){const i=o("Badge");return l(),s("div",null,[t(i,{variant:"red"},{default:a(()=>[...e[0]||(e[0]=[r("Medicalized System",-1)])]),_:1}),t(i,{variant:"blue"},{default:a(()=>[...e[1]||(e[1]=[r("Strong Anti-Discrimination Laws",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="legal-rights-in-switzerland" tabindex="-1">Legal Rights in Switzerland <a class="header-anchor" href="#legal-rights-in-switzerland" aria-label="Permalink to &quot;Legal Rights in Switzerland&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Switzerland operates a <strong>medicalized model</strong> for legal gender recognition. A reform bill (self-determination model) has been proposed but as of 2026 has not yet been passed.</p><h3 id="current-requirements" tabindex="-1">Current Requirements <a class="header-anchor" href="#current-requirements" aria-label="Permalink to &quot;Current Requirements&quot;">​</a></h3><ul><li>Psychiatric diagnosis of gender dysphoria (ICD-11 or DSM-5)</li><li>Court application to change legal gender</li><li>Medical reports from qualified professionals</li><li>No explicit surgery or sterilization requirement (sterilization was removed as a requirement in practice)</li><li>Minimum age: 18</li></ul><h3 id="process" tabindex="-1">Process <a class="header-anchor" href="#process" aria-label="Permalink to &quot;Process&quot;">​</a></h3><ol><li>Obtain psychiatric diagnosis (1-3 sessions with a psychiatrist)</li><li>Collect medical reports supporting the gender change</li><li>Submit application to the local district court (Bezirksgericht)</li><li>Court hearing may be required</li><li>Court decision typically takes 2-6 months</li></ol><h3 id="pending-reform" tabindex="-1">Pending Reform <a class="header-anchor" href="#pending-reform" aria-label="Permalink to &quot;Pending Reform&quot;">​</a></h3><p>A <strong>self-determination bill</strong> has been proposed that would allow gender self-declaration without medical involvement. As of 2026, this reform has not yet passed, but advocacy continues.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><ul><li>Name changes can be applied for separately from gender marker change</li><li>Requires application to the civil registry office (Zivilstandsamt)</li><li>Legal gender change usually results in automatic name change</li><li>Name-only changes for trans people require a medical certificate in practice</li></ul><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><p>Switzerland has comprehensive but fragmented anti-discrimination protections:</p><ul><li><strong>Federal Constitution</strong> — Article 8 guarantees equality before the law</li><li><strong>Criminal Code</strong> — Article 261bis prohibits discrimination based on race, ethnicity, religion, and sexual orientation; gender identity is increasingly recognized</li><li><strong>Employment Law</strong> — General protections against unfair dismissal</li><li><strong>Cantonal variations</strong> — Some cantons (Zurich, Geneva, Bern, Basel-Stadt) have stronger protections than others</li></ul><p>The <strong>Federal Act on Gender Equality</strong> provides some protections, but gender identity is not explicitly listed in all cantonal laws.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><ul><li>Switzerland&#39;s Criminal Code (Article 261bis) covers hate speech and incitement to hatred</li><li>Gender identity is not explicitly named in federal hate crime law</li><li>Some cantons include gender identity in their hate crime provisions</li><li>In practice, prosecution varies significantly by canton</li><li>Advocacy groups are pushing for federal-level inclusion of gender identity</li></ul><h2 id="document-recognition" tabindex="-1">Document Recognition <a class="header-anchor" href="#document-recognition" aria-label="Permalink to &quot;Document Recognition&quot;">​</a></h2><ul><li>Updated gender markers on Swiss passports and IDs recognized internationally</li><li>Swiss passports allow &quot;X&quot; marker (diverse/divers) since 2022</li><li>Process for &quot;X&quot; marker requires medical documentation</li><li>Swiss ID cards also support updated markers</li><li>Recognized under Swiss and international travel regulations</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Status</th></tr></thead><tbody><tr><td>Gender Recognition</td><td>Medicalized (court-based)</td></tr><tr><td>Self-ID Reform</td><td>Proposed, not passed</td></tr><tr><td>Surgery Required</td><td>No (removed in practice)</td></tr><tr><td>Third Gender</td><td>Available (&quot;divers&quot; marker)</td></tr><tr><td>Anti-Discrimination</td><td>Comprehensive but fragmented</td></tr><tr><td>Hate Crime Protections</td><td>Limited (not explicitly trans)</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.tgns.ch/" target="_blank" rel="noreferrer">Transgender Network Switzerland (TGNS)</a></li><li><a href="https://www.pinkcross.ch/" target="_blank" rel="noreferrer">Pink Cross</a></li><li><a href="https://www.bj.admin.ch/" target="_blank" rel="noreferrer">Federal Office of Justice</a></li><li><a href="https://www.ilga-europe.org/" target="_blank" rel="noreferrer">ILGA-Europe - Switzerland Report</a></li></ul>',23))])}const q=n(c,[["render",h]]);export{w as __pageData,q as default};
